// -----------------------------------------------------------------------
// ISPC layout test
//
// Layout under test:
//
//   root (chunk 0, slot 0)  800x600, vertical, pad=10, gap=5
//   └── chunk 1
//       ├── slot 0  fixed   200 x 30
//       ├── slot 1  flex=1  (takes remaining height)
//       └── slot 2  fixed   200 x 40
//
// Expected after wz_layout():
//   slot 0: x=10  y=10  w=200 h=30
//   slot 1: x=10  y=45  w=200 h=<800-30-40-2*5-2*10> = 700
//   slot 2: x=10  y=750 w=200 h=40
// -----------------------------------------------------------------------
static void wz_layout_ispc_test(void)
{
#define TEST_CHUNK_SIZE 8

	// WzChunk and WzSlot types come from WzLayout_ispc.h
	struct WzChunk chunks[2];
	struct WzSlot  slots[2];   // one SOA group per chunk

	memset(chunks, 0, sizeof(chunks));
	memset(slots, 0, sizeof(slots));

	// ---- chunk 0: root ----
	chunks[0].pad_left = 10;
	chunks[0].pad_right = 10;
	chunks[0].pad_top = 10;
	chunks[0].pad_bottom = 10;
	chunks[0].child_gap = 5;
	chunks[0].is_horizontal = 0;
	chunks[0].child_count = 3;
	chunks[0].parent_chunk = 0;
	chunks[0].parent_slot = 0;
	chunks[0].cursor_x = chunks[0].pad_left;
	chunks[0].cursor_y = chunks[0].pad_top;

	// root available space = window size (written into slot 0 of chunk 0)
	slots[0].avail_width[0] = 800;
	slots[0].avail_height[0] = 600;

	// ---- chunk 1: three children of root ----
	chunks[1].pad_left = 0;
	chunks[1].pad_right = 0;
	chunks[1].pad_top = 0;
	chunks[1].pad_bottom = 0;
	chunks[1].child_gap = 0;
	chunks[1].is_horizontal = 0;   // vertical
	chunks[1].child_count = 3;
	chunks[1].parent_chunk = 0;
	chunks[1].parent_slot = 0;
	chunks[1].cursor_x = 0;
	chunks[1].cursor_y = 0;

	slots[1].min_width[0] = 200;  slots[1].min_height[0] = 30;  slots[1].flex[0] = 0;
	slots[1].min_width[1] = 200;  slots[1].min_height[1] = 0;   slots[1].flex[1] = 1;
	slots[1].min_width[2] = 200;  slots[1].min_height[2] = 40;  slots[1].flex[2] = 0;

	wz_layout_chunks(chunks, slots, 2);

	SDL_Log("---- wz_layout ISPC test ----");
	for (int chunk = 0; chunk < 2; ++chunk)
	{
		for (int slot = 0; slot < TEST_CHUNK_SIZE; ++slot)
		{
			float w = slots[chunk].abs_width[slot];
			float h = slots[chunk].abs_height[slot];
			if (w == 0.f && h == 0.f) continue;

			SDL_Log("  chunk %d  slot %d :  x=%.0f  y=%.0f  w=%.0f  h=%.0f",
				chunk, slot,
				slots[chunk].abs_x[slot], slots[chunk].abs_y[slot],
				w, h);
		}
	}
	SDL_Log("------------------------------");
}

// -----------------------------------------------------------------------
// wz_layout_draw_test  –  visual verification of all ISPC layout features.
//
// Layout tree (vertical root, 4 feature rows):
//   Chunk 0 (root, vertical)
//     Chunk 1 → row 0 (red):    MARGINS      – middle child has margin_l/r=24
//     Chunk 2 → row 1 (green):  MAX WIDTH    – 3 flex children, middle capped at 100px
//     Chunk 3 → row 2 (blue):   CROSS-ALIGN  – 4 children: top/ref/center/bottom  + borders
//     Chunk 4 → row 3 (yellow): SHRINK-TO-H  – shrink_h=1, row stays at content height
//
// chunks[5..BENCH_CHUNKS-1]: self-referential benchmark noise (no visual effect)
// -----------------------------------------------------------------------
#define BENCH_CHUNKS 1024
static void wz_layout_draw_test(SDL_Renderer* renderer, WzDrawCommandBuffer* out)
{
	static struct WzChunk chunks[BENCH_CHUNKS];
	static struct WzSlot  slots[BENCH_CHUNKS];
	memset(chunks, 0, sizeof(chunks));
	memset(slots, 0, sizeof(slots));

	// -----------------------------------------------------------------
	// Chunk 0: root  (vertical, 4 rows)
	// -----------------------------------------------------------------
	chunks[0].pad_left = 16; chunks[0].pad_right = 16;
	chunks[0].pad_top = 16; chunks[0].pad_bottom = 16;
	chunks[0].child_gap = 12;
	chunks[0].child_count = 4;
	chunks[0].is_horizontal = 0;
	chunks[0].parent_chunk = 0;  chunks[0].parent_slot = 0;
	chunks[0].cursor_x = 16; chunks[0].cursor_y = 16;
	slots[0].avail_width[0] = WINDOW_WIDTH;
	slots[0].avail_height[0] = WINDOW_HEIGHT;
	// flex[3]=3 matches chunks[0].flex_total (accumulated from chunk 2's 3 flex children),
	// so the yellow shrink row receives ALL remaining window height — then shrink_h clamps it.
	slots[0].flex[3] = 3;

	// -----------------------------------------------------------------
	// Chunk 1: MARGINS demo  (red row)
	//   3 children. Child[1] has margin_l=margin_r=24.
	//   Visible: child[1] box is inset 24px from its allocated footprint.
	// -----------------------------------------------------------------
	chunks[1].pad_left = 8;  chunks[1].pad_right = 8;
	chunks[1].pad_top = 8;  chunks[1].pad_bottom = 8;
	chunks[1].child_gap = 8;
	chunks[1].child_count = 3;
	chunks[1].is_horizontal = 1;
	chunks[1].parent_chunk = 0;  chunks[1].parent_slot = 0;
	chunks[1].cursor_x = 8;  chunks[1].cursor_y = 8;
	slots[1].min_width[0] = 100;  slots[1].min_height[0] = 50;
	slots[1].min_width[1] = 100;  slots[1].min_height[1] = 50;
	slots[1].margin_left[1] = 24; slots[1].margin_right[1] = 24; // <-- margins
	slots[1].min_width[2] = 100;  slots[1].min_height[2] = 50;

	// -----------------------------------------------------------------
	// Chunk 2: MAX WIDTH demo  (green row)
	//   3 flex=1 children. Child[1] has max_w=100 — stays narrow; others grow.
	// -----------------------------------------------------------------
	chunks[2].pad_left = 8;  chunks[2].pad_right = 8;
	chunks[2].pad_top = 8;  chunks[2].pad_bottom = 8;
	chunks[2].child_gap = 8;
	chunks[2].child_count = 3;
	chunks[2].is_horizontal = 1;
	chunks[2].parent_chunk = 0;  chunks[2].parent_slot = 1;
	chunks[2].cursor_x = 8;  chunks[2].cursor_y = 8;
	slots[2].min_width[0] = 60;  slots[2].min_height[0] = 50;  slots[2].flex[0] = 1;
	slots[2].min_width[1] = 60;  slots[2].min_height[1] = 50;  slots[2].flex[1] = 1;
	slots[2].max_width[1] = 100; // <-- max width cap
	slots[2].min_width[2] = 60;  slots[2].min_height[2] = 50;  slots[2].flex[2] = 1;

	// -----------------------------------------------------------------
	// Chunk 3: CROSS-AXIS ALIGNMENT demo  (blue row)  + visible border
	//   4 children, same width, different heights:
	//     [0] h=40  cross_align=0    → top
	//     [1] h=90  cross_align=0    → reference (tallest, defines inner_h)
	//     [2] h=40  cross_align=0.5  → vertically centered
	//     [3] h=40  cross_align=1.0  → bottom
	// -----------------------------------------------------------------
	chunks[3].pad_left = 8;  chunks[3].pad_right = 8;
	chunks[3].pad_top = 8;  chunks[3].pad_bottom = 8;
	chunks[3].border_left = 3;  chunks[3].border_right = 3;
	chunks[3].border_top = 3;  chunks[3].border_bottom = 3;
	chunks[3].child_gap = 8;
	chunks[3].child_count = 4;
	chunks[3].is_horizontal = 1;
	chunks[3].parent_chunk = 0;  chunks[3].parent_slot = 2;
	chunks[3].cursor_x = 8 + 3;  // pad + border
	chunks[3].cursor_y = 8 + 3;
	slots[3].min_width[0] = 90;  slots[3].min_height[0] = 40;  slots[3].cross_align[0] = 0.0f;
	slots[3].min_width[1] = 90;  slots[3].min_height[1] = 90;  slots[3].cross_align[1] = 0.0f; // ref
	slots[3].min_width[2] = 90;  slots[3].min_height[2] = 40;  slots[3].cross_align[2] = 0.5f;
	slots[3].min_width[3] = 90;  slots[3].min_height[3] = 40;  slots[3].cross_align[3] = 1.0f;

	// -----------------------------------------------------------------
	// Chunk 4: SHRINK-TO-HEIGHT demo  (yellow row)
	//   slots[0].flex[3]=3 gives this row all extra window height.
	//   shrink_h=1 clamps it back to its natural content height.
	//   Without shrink_h the yellow row would fill the rest of the screen.
	// -----------------------------------------------------------------
	chunks[4].pad_left = 8;  chunks[4].pad_right = 8;
	chunks[4].pad_top = 8;  chunks[4].pad_bottom = 8;
	chunks[4].child_gap = 8;
	chunks[4].child_count = 3;
	chunks[4].is_horizontal = 1;
	chunks[4].parent_chunk = 0;  chunks[4].parent_slot = 3;
	chunks[4].cursor_x = 8;  chunks[4].cursor_y = 8;
	chunks[4].shrink_height = 1;  // <-- shrink
	slots[4].min_width[0] = 80;  slots[4].min_height[0] = 50;
	slots[4].min_width[1] = 80;  slots[4].min_height[1] = 50;
	slots[4].min_width[2] = 80;  slots[4].min_height[2] = 50;

	// Benchmark chunks: self-referential so Pass 1 writes into own slots only
	for (int i = 5; i < BENCH_CHUNKS; ++i)
	{
		chunks[i].pad_left = 4;  chunks[i].pad_right = 4;
		chunks[i].child_gap = 2;
		chunks[i].is_horizontal = i % 2;
		chunks[i].child_count = 4;
		chunks[i].parent_chunk = i;
		chunks[i].parent_slot = 0;
		chunks[i].cursor_x = 4;  chunks[i].cursor_y = 4;
		for (int j = 0; j < 4; ++j)
		{
			slots[i].min_width[j] = 40.f + (float)(j * 10);
			slots[i].min_height[j] = 20.f + (float)(j * 5);
		}
	}

	Uint64 t0 = SDL_GetPerformanceCounter();
	wz_layout_chunks(chunks, slots, BENCH_CHUNKS);
	Uint64 t1 = SDL_GetPerformanceCounter();
	double ms = (double)(t1 - t0) * 1000.0 / (double)SDL_GetPerformanceFrequency();

	SDL_SetRenderDrawBlendMode(renderer, SDL_BLENDMODE_BLEND);

	// -----------------------------------------------------------------
	// Draw row backgrounds  (slots[0][0..3])
	// -----------------------------------------------------------------
	static const unsigned row_col[4] = {
		WZ_RGBA(220,  80,  80, 150),   // red    – margins
		WZ_RGBA(60, 170,  60, 150),   // green  – max_w
		WZ_RGBA(50,  90, 210, 150),   // blue   – cross_align
		WZ_RGBA(210, 190,  50, 150),   // yellow – shrink
	};
	for (int j = 0; j < 4; ++j)
	{
		wz_ispc_push_rect(out, &slots[0], j, row_col[j]);
		SDL_FRect r = { slots[0].abs_x[j], slots[0].abs_y[j],
						slots[0].abs_width[j], slots[0].abs_height[j] };
		SDL_SetRenderDrawColor(renderer, 255, 255, 255, 200);
		SDL_RenderRect(renderer, &r);
	}

	// -----------------------------------------------------------------
	// Row 0 (red): MARGINS  – slots[1][0..2]
	//   Child[1] is lighter; also draw its margin footprint as dim rect.
	// -----------------------------------------------------------------
	static const unsigned margin_col[3] = {
		WZ_RGBA(150, 40, 40, 230), WZ_RGBA(255, 140, 140, 230), WZ_RGBA(150, 40, 40, 230)
	};
	for (int j = 0; j < 3; ++j)
	{
		wz_ispc_push_rect(out, &slots[1], j, margin_col[j]);
		SDL_FRect r = { slots[1].abs_x[j], slots[1].abs_y[j],
						slots[1].abs_width[j], slots[1].abs_height[j] };
		SDL_SetRenderDrawColor(renderer, 255, 255, 255, 160);
		SDL_RenderRect(renderer, &r);
	}
	// Margin footprint of child[1]: the area including its margins
	{
		SDL_FRect fp = {
			slots[1].abs_x[1] - slots[1].margin_left[1],
			slots[1].abs_y[1],
			slots[1].abs_width[1] + slots[1].margin_left[1] + slots[1].margin_right[1],
			slots[1].abs_height[1]
		};
		SDL_SetRenderDrawColor(renderer, 255, 220, 100, 120);
		SDL_RenderRect(renderer, &fp);
	}

	// -----------------------------------------------------------------
	// Row 1 (green): MAX WIDTH  – slots[2][0..2]
	//   Child[1] (middle, lighter) is the capped one.
	// -----------------------------------------------------------------
	static const unsigned max_col[3] = {
		WZ_RGBA(30, 130, 30, 230), WZ_RGBA(160, 255, 160, 230), WZ_RGBA(30, 130, 30, 230)
	};
	for (int j = 0; j < 3; ++j)
	{
		wz_ispc_push_rect(out, &slots[2], j, max_col[j]);
		SDL_FRect r = { slots[2].abs_x[j], slots[2].abs_y[j],
						slots[2].abs_width[j], slots[2].abs_height[j] };
		SDL_SetRenderDrawColor(renderer, 255, 255, 255, 160);
		SDL_RenderRect(renderer, &r);
	}

	// -----------------------------------------------------------------
	// Row 2 (blue): CROSS-ALIGN  – slots[3][0..3]
	//   Draw border stripes first, then children.
	// -----------------------------------------------------------------
	{
		float bx = slots[0].abs_x[2], by = slots[0].abs_y[2];
		float bw = slots[0].abs_width[2], bh = slots[0].abs_height[2];
		float bl = chunks[3].border_left, br = chunks[3].border_right;
		float bt = chunks[3].border_top, bb = chunks[3].border_bottom;
		unsigned border_color = WZ_RGBA(180, 210, 255, 255);
		wz_push_filled_rect(out, bx, by, bw, bt, border_color);
		wz_push_filled_rect(out, bx, by + bh - bb, bw, bb, border_color);
		wz_push_filled_rect(out, bx, by, bl, bh, border_color);
		wz_push_filled_rect(out, bx + bw - br, by, br, bh, border_color);
	}
	static const unsigned align_col[4] = {
		WZ_RGBA(20,  60, 170, 230),   // top
		WZ_RGBA(100, 160, 255, 230),   // reference (tallest)
		WZ_RGBA(20,  60, 170, 230),   // center
		WZ_RGBA(20,  60, 170, 230),   // bottom
	};
	for (int j = 0; j < 4; ++j)
	{
		wz_ispc_push_rect(out, &slots[3], j, align_col[j]);
		SDL_FRect r = { slots[3].abs_x[j], slots[3].abs_y[j],
						slots[3].abs_width[j], slots[3].abs_height[j] };
		SDL_SetRenderDrawColor(renderer, 255, 255, 255, 160);
		SDL_RenderRect(renderer, &r);
	}

	// -----------------------------------------------------------------
	// Row 3 (yellow): SHRINK  – slots[4][0..2]
	// -----------------------------------------------------------------
	static const unsigned shrink_col[3] = {
		WZ_RGBA(170, 150, 20, 230), WZ_RGBA(255, 240, 90, 230), WZ_RGBA(170, 150, 20, 230)
	};
	for (int j = 0; j < 3; ++j)
	{
		wz_ispc_push_rect(out, &slots[4], j, shrink_col[j]);
		SDL_FRect r = { slots[4].abs_x[j], slots[4].abs_y[j],
						slots[4].abs_width[j], slots[4].abs_height[j] };
		SDL_SetRenderDrawColor(renderer, 255, 255, 255, 160);
		SDL_RenderRect(renderer, &r);
	}

	// -----------------------------------------------------------------
	// Feature labels
	// -----------------------------------------------------------------
	static const char* const labels[4] = {
		"MARGINS: child[1] has margin_l/r=24 (yellow outline = footprint)",
		"MAX_W:   child[1] flex=1 but capped at 100px; others expand",
		"CROSS_ALIGN: [0]=top  [1]=ref  [2]=center  [3]=bottom  (+ 3px border)",
		"SHRINK_H: row has flex but shrink_h=1 keeps it at content height",
	};
	for (int j = 0; j < 4; ++j)
	{
		int llen = (int)SDL_strlen(labels[j]);
		render_text(renderer, &fonts[0], labels[j],
			(int)slots[0].abs_x[j] + 4,
			(int)slots[0].abs_y[j] + 2,
			font_heights[0], llen);
	}

	// -----------------------------------------------------------------
	// Timing label (top-right)
	// -----------------------------------------------------------------
	char buf[40];
	int len = SDL_snprintf(buf, sizeof(buf), "ISPC: %.4f ms", ms);
	float tw = 0, th = 0;
	get_string_size(buf, 0, len, 0, &tw, &th);
	wz_push_filled_rect(out, WINDOW_WIDTH - tw - 14, 6, tw + 10, th + 4, WZ_RGBA(0, 0, 0, 160));
	render_text(renderer, &fonts[0], buf, (int)(WINDOW_WIDTH - tw - 9), 8, th, len);
}

void wz_layout_new()
{
#if 0
	chunks.available_width[0][0] = FLT_MAX;
	chunks.available_height[0][0] = FLT_MAX;

#if 0
	// --- Init root ---
	chunks.minimum_width[0][0] = 1000;
	chunks.minimum_height[0][0] = 1000;
	chunks.available_width[0][0] = 1000;
	chunks.available_height[0][0] = 1000;
	chunks.absolute_width[0][0] = 1000;
	chunks.absolute_height[0][0] = 1000;

	chunks.padding_left[0] = 5;
	chunks.padding_right[0] = 5;
	chunks.padding_top[0] = 5;
	chunks.padding_bottom[0] = 5;
	chunks.child_gap[0] = 20;
	chunks.is_horizontal[0] = false;
	chunks.children_count[0] = 0;
	chunks.children_flex_total[0] = 0;
	chunks.layout_cursor_x[0] = 5;
	chunks.layout_cursor_y[0] = 5;

	wz->widgets[0].actual_x = chunks.absolute_x[0][0];
	wz->widgets[0].actual_y = chunks.absolute_y[0][0];
	wz->widgets[0].actual_w = chunks.absolute_width[0][0];
	wz->widgets[0].actual_h = chunks.absolute_height[0][0];

	// --- Widget creation ---
	WzWidgetNew parent = { .child_chunk = 1 };

	WzWidgetNew w = create_widget(&parent);
	chunks.minimum_width[w.chunk][w.index_in_chunk] = 50;
	chunks.minimum_height[w.chunk][w.index_in_chunk] = 50;

	for (unsigned i = 0; i < 2; ++i)
	{
		WzWidgetNew w = create_widget(&parent);
		chunks.minimum_width[w.chunk][w.index_in_chunk] = 10;
		chunks.minimum_height[w.chunk][w.index_in_chunk] = 10;
		chunks.flex[w.chunk][w.index_in_chunk] = (float)(1 + i);
	}
#else

#endif

	// ----------------------------------------------------------------
	// Pass 1: bottom-up minimum size
	// ----------------------------------------------------------------
	for (int i = MAX_NUM_CHUNKS - 1; i > 0; --i)
	{
		unsigned parent_chunk = chunks_data[i].parent_chunk;
		unsigned parent_slot = chunks_data[i].parent_index_inside_chunk;

		float total_width = 0, total_height = 0;
		float biggest_width = 0, biggest_height = 0;
		float total_flex = 0;

		float* minimum_width = chunks.minimum_width[i];
		float* minimum_height = chunks.minimum_height[i];
		float* flex = chunks.flex[i];

		for (unsigned j = 0; j < CHUNK_SIZE; ++j)
		{
			total_width += minimum_width[j];
			total_height += minimum_height[j];
			biggest_width = fmaxf(biggest_width, minimum_width[j]);
			biggest_height = fmaxf(biggest_height, minimum_height[j]);
			total_flex += flex[j];
		}

		chunks.children_flex_total[parent_chunk] += (unsigned)total_flex;

		total_width = fmaxf(total_width, chunks.minimum_width[parent_chunk][parent_slot]);
		total_height = fmaxf(total_height, chunks.minimum_height[parent_chunk][parent_slot]);

		chunks.minimum_width[parent_chunk][parent_slot] = chunks.is_horizontal[parent_chunk] ? total_width : biggest_width;
		chunks.minimum_height[parent_chunk][parent_slot] = !chunks.is_horizontal[parent_chunk] ? total_height : biggest_height;
	}

	// ----------------------------------------------------------------
	// Pass 2: top-down available space
	// ----------------------------------------------------------------
	for (int i = 0; i < MAX_NUM_CHUNKS; ++i)
	{
		unsigned parent_chunk = chunks_data[i].parent_chunk;
		unsigned parent_slot = chunks_data[i].parent_index_inside_chunk;

		float space_width = chunks.available_width[parent_chunk][parent_slot];
		float space_height = chunks.available_height[parent_chunk][parent_slot];

		space_width -= chunks.padding_left[parent_chunk] + chunks.padding_right[parent_chunk];
		space_height -= chunks.padding_top[parent_chunk] + chunks.padding_bottom[parent_chunk];
		space_width -= chunks.is_horizontal[parent_chunk] ? chunks.child_gap[parent_chunk] * (chunks.children_count[parent_chunk] - 1) : 0;
		space_height -= chunks.is_horizontal[parent_chunk] ? 0 : chunks.child_gap[parent_chunk] * (chunks.children_count[parent_chunk] - 1);

		float* minimum_width = chunks.minimum_width[i];
		float* minimum_height = chunks.minimum_height[i];
		float* available_width = chunks.available_width[i];
		float* available_height = chunks.available_height[i];

		for (unsigned j = 0; j < CHUNK_SIZE; ++j)
		{
			space_width -= minimum_width[j];
			space_height -= minimum_height[j];
			available_width[j] += minimum_width[j];
			available_height[j] += minimum_height[j];
		}

		float width_per_flex = chunks.children_flex_total[parent_chunk] > 0 ? space_width / chunks.children_flex_total[parent_chunk] : 0;
		float height_per_flex = chunks.children_flex_total[parent_chunk] > 0 ? space_height / chunks.children_flex_total[parent_chunk] : 0;

		float* flex = chunks.flex[i];
		bool   is_horizontal = chunks.is_horizontal[parent_chunk];

		for (unsigned j = 0; j < CHUNK_SIZE; ++j)
		{
			available_width[j] += is_horizontal ? flex[j] * width_per_flex : 0;
			available_height[j] += !is_horizontal ? flex[j] * height_per_flex : 0;
		}
	}

	// ----------------------------------------------------------------
	// Pass 3: available -> absolute
	// ----------------------------------------------------------------
	for (int i = 0; i < MAX_NUM_CHUNKS; ++i)
	{
		float* available_width = chunks.available_width[i];
		float* available_height = chunks.available_height[i];
		float* absolute_width = chunks.absolute_width[i];
		float* absolute_height = chunks.absolute_height[i];

		for (unsigned j = 0; j < CHUNK_SIZE; ++j)
		{
			absolute_width[j] = available_width[j];
			absolute_height[j] = available_height[j];
		}
	}

	// ----------------------------------------------------------------
	// Pass 4: assert parent space non-negative (debug only)
	// ----------------------------------------------------------------
	for (int i = 1; i < MAX_NUM_CHUNKS; ++i)
	{
		unsigned parent_chunk = chunks_data[i].parent_chunk;
		unsigned parent_slot = chunks_data[i].parent_index_inside_chunk;
		wz_assert(chunks.available_width[parent_chunk][parent_slot] >= 0);
		wz_assert(chunks.available_height[parent_chunk][parent_slot] >= 0);
	}

	// ----------------------------------------------------------------
	// Pass 5: write widget positions (serial)
	// ----------------------------------------------------------------
	for (unsigned i = 0; i < MAX_NUM_CHUNKS; ++i)
	{
		unsigned parent_chunk = chunks_data[i].parent_chunk;
		unsigned parent_slot = chunks_data[i].parent_index_inside_chunk;

		float parent_absolute_x = chunks.absolute_x[parent_chunk][parent_slot];
		float parent_absolute_y = chunks.absolute_y[parent_chunk][parent_slot];
		bool  is_horizontal = chunks.is_horizontal[parent_chunk];
		float gap = chunks.child_gap[parent_chunk];
		; \
			for (unsigned j = 0; j < CHUNK_SIZE; ++j)
			{
				float absolute_width = chunks.absolute_width[i][j];
				float absolute_height = chunks.absolute_height[i][j];

				chunks.absolute_x[i][j] = parent_absolute_x + chunks.layout_cursor_x[parent_chunk];
				chunks.absolute_y[i][j] = parent_absolute_y + chunks.layout_cursor_y[parent_chunk];

				chunks.layout_cursor_x[parent_chunk] += is_horizontal ? absolute_width + gap : 0;
				chunks.layout_cursor_y[parent_chunk] += !is_horizontal ? absolute_height + gap : 0;
			}
	}

	unsigned widgets_count = 0;

	for (unsigned i = 0; i < MAX_NUM_CHUNKS; ++i)
	{
		for (unsigned j = 0; j < CHUNK_SIZE; ++j)
		{
			if (chunks.absolute_width[i][j])
			{
				wz->widgets[widgets_count].actual_w = chunks.absolute_width[i][j];
				wz->widgets[widgets_count].actual_h = chunks.absolute_height[i][j];
				wz->widgets[widgets_count].actual_x = chunks.absolute_x[i][j];
				wz->widgets[widgets_count].actual_y = chunks.absolute_y[i][j];

				widgets_count++;
				widgets_count &= MAX_NUM_WIDGETS - 1;
				wz_assert(widgets_count < MAX_NUM_WIDGETS);
			}
		}
	}
#endif
}